// Initialize variables
let combinedText = "";
let count = 0;

// Loop through the items returned by the AI Agent
for (const item of items) {
  if (item.json.output) {
    count++;

    // We do NOT need to look up original records anymore.
    // The AI output already has the Client Name header.

    // Append the text + a separator line
    combinedText += item.json.output + "\n\n-----------------------------------\n\n";
  }
}

return [
  {
    json: {
      aggregatedUpdates: combinedText,
      totalCount: count
    }
  }
];

// 1. GET DATA
// The AI returns the JSON as a text string inside 'output'
const aiOutputText = items[0].json.output;

// 2. PARSE THE JSON
// Convert that text string into a real JavaScript Array
let updatesArray = [];
try {
    // We clean it just in case the AI added markdown ticks (```json ... ```)
    const cleanText = aiOutputText.replace(/```json/g, "").replace(/```/g, "").trim();
    updatesArray = JSON.parse(cleanText);
} catch (error) {
    // Safety net: If parsing fails, create a dummy error card
    updatesArray = [{
        clientName: "Error Parsing Data",
        latestUpdate: "The AI output could not be converted to JSON.",
        statusType: "warning"
    }];
}

// 3. START HTML CONTAINER (Orange Header)
let finalHTML = `
<div style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto; border: 1px solid #e0e0e0; border-radius: 8px; overflow: hidden; background-color: #ffffff;">
    <div style="background-color: #f37021; padding: 20px; text-align: center; color: white;">
        <h2 style="margin: 0; font-size: 20px; font-weight: bold;">Daily Reporting</h2>
        <p style="margin: 5px 0 0 0; font-size: 14px; opacity: 0.9;">Summary of today's activity</p>
    </div>

    <div style="padding: 0 20px;">
`;

// 4. LOOP THROUGH DATA & BUILD CARDS
for (let i = 0; i < updatesArray.length; i++) {
    const record = updatesArray[i];

    // COLOR LOGIC: Green for Success/Neutral, Red for Warning
    // You can customize this logic if you want different colors for "neutral"
    let dotColor = "#2ecc71"; // Default Green
    if (record.statusType === 'warning') {
        dotColor = "#e74c3c"; // Red
    }

    // SEPARATOR LOGIC: Add a border for all items EXCEPT the last one
    const borderStyle = (i === updatesArray.length - 1) ? "" : "border-bottom: 1px solid #eee;";

    finalHTML += `
        <div style="padding: 20px 0; ${borderStyle}">
            <div style="display: flex; align-items: center; margin-bottom: 8px;">
                <span style="height: 10px; width: 10px; background-color: ${dotColor}; border-radius: 50%; display: inline-block; margin-right: 12px; flex-shrink: 0;"></span>

                <h3 style="margin: 0; font-size: 16px; color: #2c3e50; font-weight: bold;">
                    ${record.clientName}
                </h3>
            </div>

            <div style="margin-left: 22px; font-size: 14px; line-height: 1.5; color: #555;">
                ${record.latestUpdate}
            </div>
        </div>
    `;
}

// 5. CLOSE CONTAINER
finalHTML += `
    </div>
</div>
`;

// 6. RETURN RESULT
return [
  {
    json: {
      htmlEmail: finalHTML,
      recordCount: updatesArray.length
    }
  }
];

